char* countAndSay(int n) {
    char* cur = (char*)malloc(2);
    strcpy(cur, "1");
    for (int k = 1; k < n; k++) {
        int len = (int)strlen(cur), cap = len * 2 + 16, pos = 0;
        char* nxt = (char*)malloc(cap);
        nxt[0] = '\0';
        for (int i = 0; cur[i]; ) {
            int j = i;
            while (cur[j] && cur[j] == cur[i]) j++;
            pos += sprintf(nxt + pos, "%d%c", j - i, cur[i]);
            i = j;
        }
        free(cur);
        cur = nxt;
    }
    return cur;
}
